blocks.body:
{
    "level": "B1–B2",
    "intro": "]W tym temacie dowiesz się o <strong>nie, żaden, żadne</strong>, kiedy ich używać i jaka jest między nimi różnica. różnica.",
    "rules": [
        {
            "label": "Nie",
            "color": "rose",
            "text": "<strong>Nie</strong> - brak (przed rzeczownikiem):",
            "example": "Żaden uczeń nie przyszedł. / Nie mam pieniędzy."
        },
        {
            "label": "Brak",
            "color": "purple",
            "text": "<strong>Brak</strong> — brak (samodzielnie):",
            "example": "Żaden z uczniów nie przyszedł. / Nie mam żadnego."
        },
        {
            "label": "Żadna/Żadna",
            "color": "blue",
            "text": "<strong>Żadna/żadna</strong> — żadna/dowolna (z dwóch):",
            "example": "Żadna opcja nie działa. / Tak czy inaczej jest w porządku."
        }
    ]
}

{
    "title": "1. Przegląd Nie / Żaden / Ani / Albo",
    "intro": "Te słowa wyrażają nieobecność lub wybór:",
    "items": [
        {
            "label": "Nie",
            "title": "Nie (znacznik)",
            "subtitle": "Używane przed rzeczownikiem: nie ma pieniędzy, nie czas"
        },
        {
            "label": "Brak",
            "title": "Brak (zaimek)",
            "subtitle": "Używane niezależnie: żadne z nich, nie mam żadnego"
        },
        {
            "label": "Żaden/Żaden",
            "title": "Z dwóch opcje",
            "subtitle": "Żadna = żadna z dwóch, Albo = żadna z dwóch"
        }
    ]
}

{
    "title": "2. Nie - brak (przed rzeczownikiem)",
    "sections": [
        {
            "label": "Główne zastosowanie",
            "color": "rose",
            "description": "<strong>Nie</strong> to przymiotnik występujący <strong>przed rzeczownikiem</strong> i oznaczający „żaden, żaden”.",
            "examples": [
                {
                    "en": "Nie mam pieniędzy.",
                    "ua": "Nie mam pieniędzy. (brak pieniędzy)"
                },
                {
                    "en": "W klasie nie ma uczniów.",
                    "ua": "W klasie nie ma uczniów."
                },
                {
                    "en": "Ona nie ma na to czasu.",
                    "ua": "Ona nie ma na to czasu."
                },
                {
                    "en": "Nie problem!",
                    "ua": "Nie ma problemu! (bez problemu)"
                }
            ]
        },
        {
            "label": "Z obydwoma typami rzeczowników",
            "color": "amber",
            "description": "<strong>No</strong> działa z <strong>rzeczownikami policzalnymi i niepoliczalnymi</strong>.",
            "examples": [
                {
                    "en": "brak książek (policzalne)",
                    "ua": "brak książek (policzalne)"
                },
                {
                    "en": "brak wody (niepoliczalne)",
                    "ua": "brak wody (niepoliczalne)"
                },
                {
                    "en": "brak przyjaciół, brak informacji",
                    "ua": "brak przyjaciół, brak informacji"
                }
            ]
        },
        {
            "label": "Nie zamiast nie any",
            "color": "sky",
            "description": "<strong>Nie</strong> to bardziej kategoryczna forma sprzeciwu.",
            "examples": [
                {
                    "en": "Nie mam pieniędzy. = Nie mam żadnych pieniędzy.",
                    "ua": "Nie mam żadnych pieniędzy."
                },
                {
                    "en": "Nie ma biletów. = Nie ma żadnych biletów.",
                    "ua": "Brak biletów."
                }
            ],
            "note": "📌 <strong>Nie</strong> jest bardziej stanowcze (kategoryczne)."
        }
    ]
}

{
    "title": "3. Brak (zaimek)",
    "sections": [
        {
            "label": "Użyj bez rzeczownika",
            "color": "purple",
            "description": "<strong>None</strong> to zaimek, który jest <strong>używany samodzielnie</strong> (bez rzeczownika po nim).",
            "examples": [
                {
                    "en": "Ile ich masz? — Brak.",
                    "ua": "Ile ich masz? — Brak."
                },
                {
                    "en": "Chciałem napić się kawy, ale nie było.",
                    "ua": "Chciałem napić się kawy, ale nie było."
                },
                {
                    "en": "Żadna nie dotarła na czas.",
                    "ua": "Żaden nie przyszedł na czas."
                }
            ]
        },
        {
            "label": "None of + noun",
            "color": "rose",
            "description": "<strong>None of</strong> + rzeczownik określony (the, this, my itp.).",
            "examples": [
                {
                    "en": "Żaden z uczniów nie zdał.",
                    "ua": "Żaden z uczniów zdane skompilowane."
                },
                {
                    "en": "Żaden z moich znajomych nie przyszedł.",
                    "ua": "Żaden z moich znajomych nie przyszedł."
                },
                {
                    "en": "Nic z tego nie jest prawdą.",
                    "ua": "Nic z tego nie jest prawdą."
                },
                {
                    "en": "Nikt z nas nie wie odpowiedź.",
                    "ua": "Nikt z nas nie zna odpowiedzi."
                }
            ]
        },
        {
            "label": "Różnica: nie vs żaden",
            "color": "sky",
            "description": "Główna różnica polega na położeniu i obecności rzeczownika.",
            "examples": [
                {
                    "en": "Żaden uczeń nie przyszedł. (przed rzeczownikiem)",
                    "ua": "Żaden uczeń nie przyszedł."
                },
                {
                    "en": "Żaden nie przyszedł. (no rzeczownik)",
                    "ua": "Żaden z uczniów nie przyszedł."
                },
                {
                    "en": "Żaden z uczniów nie przyszedł. (of + noun)",
                    "ua": "Żaden z uczniów nie przyszedł."
                }
            ],
            "note": "📌 <strong>Nie</strong> + rzeczownik, <strong>Żaden</strong> — niezależnie lub z of."
        }
    ]
}

{
    "title": "4. Żadna opcja nie jest dobra. dobrze.",
    "sections": [
        {
            "label": "Негативний вибір з двох",
            "color": "blue",
            "description": "<strong>Neither</strong> означає «<strong>жоден з двох</strong>» (негативне значення).",
            "examples": [
                {
                    "en": "Neither option is good.",
                    "ua": "Жоден з двох варіантів не хороший."
                },
                {
                    "en": "Żadna odpowiedź nie jest poprawna.",
                    "ua": "Żadna z dwóch odpowiedzi nie jest poprawna."
                },
                {
                    "en": "Żadna drużyna nie wygrała.",
                    "ua": "Żadna z dwóch drużyn nie wygrała."
                }
            ]
        },
        {
            "label": "Żadna z drużyn nie wygrała of + rzeczownik",
            "color": "purple",
            "description": "<strong>Żaden z</strong> + zdefiniowany rzeczownik w liczbie mnogiej.",
            "examples": [
                {
                    "en": "Żadna z książek nie jest interesująca.",
                    "ua": "Żadna z nich nie przyszła."
                },
                {
                    "en": "Neither of them came.",
                    "ua": "Żadna z nich (dwie) nie przyszła."
                },
                {
                    "en": "Żaden z moich rodziców nie mówi po angielsku.",
                    "ua": "Żadne z moich rodziców nie mówi Angielski."
                }
            ]
        },
        {
            "label": "Ani... ani...",
            "color": "rose",
            "description": "Konstrukcja <strong>ani... ani...</strong> to "nie... nie...".",
            "examples": [
                {
                    "en": "Ani John, ani Mary nie przyszli.",
                    "ua": "Ani John, ani Mary przyszedł."
                },
                {
                    "en": "Nie lubię ani herbaty, ani kawy.",
                    "ua": "Nie lubię herbaty ani kawy."
                },
                {
                    "en": "Nie jest ani gorąco, ani zimno.",
                    "ua": "Nie jest ani gorąco, ani zimno."
                }
            ],
            "note": "⚠️ <strong>Żadne</strong> nie zawiera już negacji — nie jest potrzebne!"
        }
    ]
}

{
    "title": "5. Albo - dowolna (z dwóch)",
    "sections": [
        {
            "label": "Pozytywny wybór dwóch",
            "color": "emerald",
            "description": "<strong>Albo</strong> oznacza „<strong>dowolny z dwóch</strong>” (wartość dodatnia).",
            "examples": [
                {
                    "en": "Każda opcja jest w porządku.",
                    "ua": "Każda z dwóch opcji "
                },
                {
                    "en": "Możesz wziąć dowolną książkę.",
                    "ua": "Możesz wziąć dowolną książkę."
                },
                {
                    "en": "W moim przypadku działa tak czy inaczej.",
                    "ua": "W moim przypadku sprawdza się każdy z dwóch sposobów."
                }
            ]
        },
        {
            "label": "Każdy z + rzeczownik",
            "color": "sky",
            "description": "<strong>Każda z</strong> + zdefiniowany rzeczownik w liczbie mnogiej.",
            "examples": [
                {
                    "en": "Każda z książek jest dobra.",
                    "ua": "Każda z dwóch książek jest dobra."
                },
                {
                    "en": "Każda z nich może pomóc Ciebie.",
                    "ua": "Każdy z nich (dwa) może Ci pomóc."
                },
                {
                    "en": "Możesz wybrać jedno z nich.",
                    "ua": "Możesz wybrać dowolną z nich (dwa)."
                }
            ]
        },
        {
            "label": "Albo... albo...",
            "color": "amber",
            "description": "Konstrukcja <strong>albo... albo...</strong> to „lub... lub…”.",
            "examples": [
                {
                    "en": "Możesz napić się herbaty lub kawy.",
                    "ua": "Możesz wziąć albo herbata, albo kawa."
                },
                {
                    "en": "Przyjdzie albo John, albo Mary.",
                    "ua": "Przyjdzie albo John, albo Mary."
                },
                {
                    "en": "Albo dobrze, albo źle.",
                    "ua": "Albo dobrze, albo źle."
                }
            ]
        }
    ]
}

{
    "title": "6. Ani vs Albo – różnica",
    "sections": [
        {
            "label": "Negatywna vs Pozytywna",
            "color": "purple",
            "description": "<strong>Żadna</strong> = żadna (negatywna), <strong>Albo</strong> = żadna (pozytywna).",
            "examples": [
                {
                    "en": "Żadna książka nie jest dobra. ❌ (żadna nie jest dobra)",
                    "ua": "Każda książka jest dobra."
                },
                {
                    "en": "Każda książka jest dobra. ✓ (albo jest dobre)",
                    "ua": "Każda z tych dwóch książek jest dobra."
                }
            ]
        },
        {
            "label": "W negacjach",
            "color": "rose",
            "description": "<strong>Albo</strong> może być również użyte w <strong>negacjach</strong> = „żadna”.",
            "examples": [
                {
                    "en": "Nie lubię kawa. — Ja też tego nie lubię.",
                    "ua": "Nie lubię kawy. - Ja też jej nie kocham. "
                },
                {
                    "en": "Ona nie może przyjść. — On też nie może przyjść.",
                    "ua": "Ona nie może przyjść. - On też nie może."
                }
            ],
            "note": "📌 W przeczeniach <strong>albo</strong> = „zbyt (nie)” i <strong>ani</strong> = „też nie” (bez nie)."
        },
        {
            "label": "Żaden vs Obydwa w zdaniach",
            "color": "sky",
            "description": "Porównanie użycie:",
            "examples": [
                {
                    "en": "Żaden z nich nie przyszedł. (żaden nie przyszedł)",
                    "ua": "Żaden z nich nie przyszedł."
                },
                {
                    "en": "Każdy z nich może przyjść. (każdy może)",
                    "ua": "Każdy z nich może przyjść."
                },
                {
                    "en": "Żadna opcja nie działa. (żadna nie działa)",
                    "ua": "Każda opcja działa."
                },
                {
                    "en": "Każda opcja działa. (każda działa)",
                    "ua": "Każda opcja działa."
                }
            ]
        }
    ]
}

{
    "title": "7. Zgodność z czasownikiem",
    "sections": [
        {
            "label": "Nie + rzeczownik",
            "color": "amber",
            "description": "Czasownik zgadza się z <strong>rzeczownikiem</strong> po nr.",
            "examples": [
                {
                    "en": "Nie ma tu żadnego ucznia. (liczba pojedyncza)",
                    "ua": "Nie ma tu żadnych uczniów."
                },
                {
                    "en": "Nie ma tu żadnych uczniów. (plural)",
                    "ua": "Nie ma tu żadnych uczniów."
                }
            ]
        },
        {
            "label": "Żaden z uczniów nie występuje w liczbie pojedynczej ani mnogiej",
            "color": "sky",
            "description": "<strong>Żaden</strong> nie może być użyty z czasownikiem <strong>w liczbie pojedynczej lub mnogiej</strong>.",
            "examples": [
                {
                    "en": "Żaden z uczniów nie jest/jest tutaj.",
                    "ua": "Nie ma tu żadnego ucznia."
                },
                {
                    "en": "Nie znaleziono żadnego. (formalne)",
                    "ua": "Nie znaleziono żadnego."
                },
                {
                    "en": "Nie znaleziono żadnego. (nieformalne)",
                    "ua": "Nic nie znaleziono."
                }
            ],
            "note": "📌 We współczesnym angielskim obie opcje są akceptowalne."
        },
        {
            "label": "Żadna/Żadna nie jest liczbą pojedynczą",
            "color": "purple",
            "description": "<strong>Żadna</strong> i <strong>albo</strong> zwykle z Czasownik <strong>w liczbie pojedynczej</strong>.",
            "examples": [
                {
                    "en": "Żadnego z nich tutaj nie ma. (formalny)",
                    "ua": "Żadnego z nich tu nie ma."
                },
                {
                    "en": "Żaden z nich jest w porządku. (formalny)",
                    "ua": "Wystarczy każdy z nich."
                }
            ],
            "note": "📌 W mowie potocznej możesz użyć liczby mnogiej: Żaden/Żaden z nich nie jest..."
        }
    ]
}

{
    "title": "8. Tabela porównawcza",
    "intro": "Основні відмінності між no, none, neither, either:",
    "rows": [
        {
            "en": "No",
            "ua": "Жодний (означник)",
            "note": "Перед іменником: no money, no students"
        },
        {
            "en": "None",
            "ua": "Жоден (займенник)",
            "note": "Samodzielnie: żaden nie przyszedł, żaden z nich"
        },
        {
            "en": "Żadna",
            "ua": "Żadna z dwóch (ujemna)",
            "note": "Żadna opcja, żadna z oni"
        },
        {
            "en": "Albo",
            "ua": "Albo z dwóch (dodatnie)",
            "note": "Albo opcja, albo z nich"
        },
        {
            "en": "Ani... ani...",
            "ua": "Nie... nie...",
            "note": "Ani herbata, ani kawa (podwójny negatywny)"
        },
        {
            "en": "Albo...albo...",
            "ua": "Albo...albo...",
            "note": "Albo herbata albo kawa (do wyboru)"
        }
    ],
    "warning": "📌 <strong>Nie</strong> — przed rzeczownikiem, <strong>None</strong> — samodzielnie, <strong>Ani/Either</strong> — z dwóch opcji!"
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak z rzeczownikiem bez.",
            "wrong": "Żaden uczeń nie przyszedł.",
            "right": " ✅ <span class="font-mono">Żaden z uczniów nie przyszedł. / Żaden uczeń nie przyszedł.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Podwójny negatywny wynik w przypadku żadnego z nich.",
            "wrong": "Żaden z nich nie przyszedł.",
            "right": " ✅ <span class="font-mono">Żaden z nich nie przyszedł. (bez!)</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Żadna/Żadna z więcej niż dwiema.",
            "wrong": "Żadna z trzech opcji nie działa.",
            "right": " ✅ <span class="font-mono">Żadna z te trzy opcje działają.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Nr z.",
            "wrong": "Żaden z uczniów nie przyszedł.",
            "right": " ✅ <span class="font-mono">Żaden z uczniów nie przyszedł. / Nie przyszedł żaden uczeń.</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwe słowo",
    "select_intro": "W każdym zdaniu wybierz nie, żadne, żadne lub jedno.",
    "selects": [
        {
            "label": "Mam ___ pieniędzy. (nie / brak)",
            "prompt": "Jakie słowo?"
        },
        {
            "label": "Ilu przyszło? — ___. (Nie / Brak)",
            "prompt": "Jakie słowo?"
        },
        {
            "label": "___ z obu książek jest dobre. (Żadne/Żadne)",
            "prompt": "Jakie słowo?"
        },
        {
            "label": "___ opcja działa w moim przypadku. Egzamin (Albo/Żaden).",
            "prompt": "Яке слово?"
        }
    ],
    "options": [
        "Перший варіант",
        "Другий варіант"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши no, none, neither або either.",
    "inputs": [
        {
            "before": "___ of the students passed the exam.",
            "after": " →"
        },
        {
            "before": "Zostało ___ jabłek.",
            "after": " →"
        },
        {
            "before": "___ z nich jest tutaj. (z dwóch)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Korekta błędów",
    "rephrase_intro": "Znajdź i popraw błąd w zdaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Żaden uczeń przyszedł.",
            "example_target": "Żaden z uczniów nie przyszedł. / Nie przyszedł żaden uczeń."
        },
        {
            "original": "1. Żaden z nich nie przyszedł.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Nie mam pieniędzy.",
            "placeholder": "Poprawka"
        }
    ]
}

{
    "title": "Inne strony z kategorii Rzeczowniki, artykuły i ilość",
    "items": [
        {
            "label": "Nie / Żadne / Żadne / Żadne (bieżące)",
            "current": true
        },
        {
            "label": "Kwantyfikatory — Dużo, Wiele, Dużo, Mało, Mały",
            "current": false
        },
        {
            "label": "Cząsteczki — kawałek, filiżanka…",
            "current": false
        },
        {
            "label": "Artykuł zerowy — Artykuł zerowy",
            "current": false
        }
    ]
}
